def shrink_tool_result(content: str, max_chars: int = 2000) -> str:
    """
    Trim oversized tool results before appending to the messages list.
    Keeps the first and last portions so the model sees both the start
    and the end of the output.
    """
    if len(content) <= max_chars:
        return content
    half = max_chars // 2
    omitted = len(content) - max_chars
    return (
        content[:half]
        + f"\n\n[... {omitted} characters omitted ...]\n\n"
        + content[-half:]
    )


def append_tool_result(
    messages: list[dict],
    tool_use_id: str,
    raw_content: str,
    max_chars: int = 2000,
) -> list[dict]:
    """
    Append a single tool result as a new user turn, shrinking if needed.
    """
    trimmed = shrink_tool_result(raw_content, max_chars)
    return messages + [
        {
            "role": "user",
            "content": [
                {
                    "type": "tool_result",
                    "tool_use_id": tool_use_id,
                    "content": trimmed,
                }
            ],
        }
    ]

def count_tokens_rough(messages: list[dict]) -> int:
    total = 0
    for m in messages:
        content = m.get("content", "")
        if isinstance(content, str):
            total += len(content)
        elif isinstance(content, list):
            for block in content:
                if isinstance(block, dict):
                    total += len(block.get("text", ""))
                    total += len(str(block.get("input", "")))
                    total += len(str(block.get("content", "")))
    return int(total * 0.25)


def trim_oldest_pairs(
    messages: list[dict],
    max_tokens: int = 160_000,
) -> list[dict]:
    """
    Drop the oldest assistant+user exchange pairs until the context
    fits within max_tokens. Always preserves messages[0] (the task).

    Invariant: messages must alternate user→assistant→user→…
    Dropping pairs (assistant at index 1, following user at index 2)
    maintains this invariant with messages[0] always a user turn.
    """
    if len(messages) <= 1:
        return messages

    while count_tokens_rough(messages) > max_tokens and len(messages) > 3:
        # messages[0] = original task (keep)
        # messages[1] = oldest assistant turn (drop)
        # messages[2] = oldest tool-result user turn (drop)
        messages = [messages[0]] + messages[3:]

    return messages


