import anthropic


def summarise_history(
    messages: list[dict],
    client: anthropic.Anthropic,
    keep_last_n: int = 4,
) -> list[dict]:
    """
    Replace the middle portion of the messages list with a single
    AI-generated summary injected as a user turn.

    messages[0]               — original task (preserved)
    messages[1 .. -(keep_last_n)] — summarised into a user turn
    messages[-(keep_last_n):]  — recent history (preserved verbatim)
    """
    if len(messages) <= keep_last_n + 1:
        return messages  # not enough history to summarise

    middle = messages[1 : -keep_last_n]
    recent = messages[-keep_last_n:]

    # Build a compact representation of the middle turns
    middle_text = "\n".join(
        f"[{m['role']}] {_content_preview(m)}"
        for m in middle
    )

    summary_response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=400,
        messages=[
            {
                "role": "user",
                "content": (
                    "Summarise the following agent conversation history in 3-5 "
                    "sentences. Focus on what was found and decided, not how.\n\n"
                    + middle_text
                ),
            }
        ],
    )
    summary_text = summary_response.content[0].text

    summary_turn = {
        "role": "user",
        "content": f"[Prior history summary]\n{summary_text}",
    }

    return [messages[0], summary_turn] + recent


def _content_preview(msg: dict, max_chars: int = 200) -> str:
    content = msg.get("content", "")
    if isinstance(content, str):
        return content[:max_chars]
    if isinstance(content, list):
        parts = []
        for block in content:
            if isinstance(block, dict):
                if block.get("type") == "text":
                    parts.append(block.get("text", "")[:max_chars])
                elif block.get("type") == "tool_use":
                    parts.append(f"tool_use:{block['name']}")
                elif block.get("type") == "tool_result":
                    parts.append(f"tool_result:{str(block.get('content',''))[:80]}")
        return " | ".join(parts)
    return ""

import pytest


class TestShrinkToolResult:
    def test_short_content_unchanged(self):
        assert shrink_tool_result("hello", max_chars=100) == "hello"

    def test_long_content_truncated(self):
        content = "A" * 5000
        result = shrink_tool_result(content, max_chars=200)
        assert len(result) < 300
        assert "omitted" in result

    def test_preserves_start_and_end(self):
        content = "START" + "x" * 5000 + "END"
        result = shrink_tool_result(content, max_chars=200)
        assert "START" in result
        assert "END" in result


class TestTrimOldestPairs:
    def _make_messages(self, n_pairs: int) -> list[dict]:
        msgs = [{"role": "user", "content": "original task"}]
        for i in range(n_pairs):
            msgs.append({"role": "assistant", "content": [
                {"type": "text", "text": "A" * 800}
            ]})
            msgs.append({"role": "user", "content": [
                {"type": "tool_result", "content": "B" * 800}
            ]})
        return msgs

    def test_preserves_task(self):
        msgs = self._make_messages(5)
        trimmed = trim_oldest_pairs(msgs, max_tokens=100)
        assert trimmed[0]["content"] == "original task"

    def test_alternating_invariant(self):
        msgs = self._make_messages(5)
        trimmed = trim_oldest_pairs(msgs, max_tokens=100)
        roles = [m["role"] for m in trimmed]
        for i in range(len(roles) - 1):
            assert roles[i] != roles[i + 1], f"consecutive same-role at {i}"

    def test_reduces_token_count(self):
        msgs = self._make_messages(10)
        before = count_tokens_rough(msgs)
        trimmed = trim_oldest_pairs(msgs, max_tokens=before // 2)
        assert count_tokens_rough(trimmed) <= before // 2 + 200  # small tolerance
